const jwt = require('jsonwebtoken')
require('dotenv').config()


const verify = async (req, res, next) => {
  try{
    const token = req.header('Authorization').replace('Bearer ', '')
    if (!token){
      throw new Error() //Error 401: Token not provided
    }
    let user = await jwt.verify(token, process.env.SECRET_KEY || 'secretkey')

    return next();
  }catch{
    res.status(401).send('Invalid token!') //Error 401: Invalid token! 
  }
}

module.exports= verify